<style>
body{background:#0f0f0f!important}
.site-header,.site-footer,header.site-header,footer.site-footer,
#masthead,#colophon,.wp-block-template-part,.navigation,.post-navigation,
.entry-header,.entry-footer,.comments-area,.sidebar,#secondary,
.wp-block-post-title{display:none!important}
.entry-content,.wp-block-post-content,.site-content,#content,.page-content,
.hentry,.wp-site-blocks{max-width:100%!important;margin:0!important;padding:0!important;background:#0f0f0f!important}
main.wp-block-group,main.wp-block-group-is-layout-constrained{margin-top:0!important;padding-top:0!important}
.wp-block-group.has-global-padding,.wp-block-group.is-layout-constrained{padding-top:0!important;margin-top:0!important}
.wp-block-html,.wp-block-html.alignfull,#ph-root{max-width:100%!important;width:100%!important}
.entry-content.has-global-padding>*,.is-layout-constrained>*,.entry-content>*{max-width:none!important}
.has-global-padding>*{max-width:none!important;--wp--style--global--content-size:100%!important;--wp--style--global--wide-size:100%!important}
/* ============================================================
   PriceHawk — shared design tokens & primitives
   Dark, trustworthy-analyst aesthetic. WireCutter × 91mobiles.
   ============================================================ */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&family=Poppins:wght@500;600;700;800&family=JetBrains+Mono:wght@400;500;600;700&display=swap');

:root {
  /* surfaces */
  --bg:        #0f0f0f;
  --bg-2:      #141414;
  --card:      #1a1a1a;
  --card-2:    #1e1e1e;
  --border:    #2a2a2a;
  --border-2:  #353535;

  /* text */
  --text:      #f0f0f0;
  --text-2:    #888888;
  --text-3:    #5f5f5f;

  /* accents */
  --accent:    #e67e22;   /* saffron / burnt orange — primary */
  --accent-h:  #f08a30;
  --green:     #27ae60;   /* deals / drops / good */
  --red:       #e74c3c;   /* price-drop %, alerts */
  --gold:      #f39c12;   /* best seller */
  --blue:      #3498db;   /* amazon's choice */

  /* fonts — --font-head is swapped by the Inter/Poppins toggle */
  --font-head: 'Inter', system-ui, sans-serif;
  --font-body: 'Inter', system-ui, sans-serif;
  --font-mono: 'JetBrains Mono', ui-monospace, monospace;
}

/* page reset scoped to artboards */
.ph {
  font-family: var(--font-body);
  background: var(--bg);
  color: var(--text);
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
  line-height: 1.5;
  position: relative;
}
.ph *, .ph *::before, .ph *::after { box-sizing: border-box; }
.ph h1, .ph h2, .ph h3, .ph h4 { font-family: var(--font-head); margin: 0; line-height: 1.12; letter-spacing: -0.02em; }
.ph p { margin: 0; }
.ph a { color: inherit; text-decoration: none; }
.ph button { font-family: inherit; cursor: pointer; }
:where(.ph button) { border: none; background: none; color: inherit; }
.ph ::selection { background: var(--accent); color: #0f0f0f; }

/* number / price typography */
.num { font-variant-numeric: tabular-nums; font-feature-settings: "tnum" 1; }
.mono { font-family: var(--font-mono); }

/* ---- price display ---------------------------------------- */
.price { display: inline-flex; align-items: baseline; gap: 9px; white-space: nowrap; }
.price .now { font-weight: 700; color: var(--text); white-space: nowrap; letter-spacing: -0.01em; }
.price .now .rupee { font-weight: 600; margin-right: 1px; }
.price .was { color: var(--text-3); text-decoration: line-through; font-weight: 500; white-space: nowrap; }
.price .off { color: var(--red); font-weight: 700; white-space: nowrap; }

/* ---- badges ----------------------------------------------- */
.badge {
  display: inline-flex; align-items: center; gap: 5px;
  font-size: 11px; font-weight: 700; letter-spacing: 0.02em;
  padding: 3px 8px; border-radius: 5px; line-height: 1.2; white-space: nowrap;
  font-family: var(--font-body);
}
.badge--seller { background: color-mix(in srgb, var(--gold) 16%, transparent); color: var(--gold); }
.badge--choice { background: color-mix(in srgb, var(--blue) 16%, transparent); color: var(--blue); }
.badge--drop   { background: color-mix(in srgb, var(--red) 16%, transparent); color: var(--red); }
.badge--staff  { background: color-mix(in srgb, var(--accent) 16%, transparent); color: var(--accent); }
.badge--solid-red  { background: var(--red); color: #fff; }
.badge--solid-green{ background: var(--green); color: #04210f; }

/* ---- buttons ---------------------------------------------- */
.btn {
  display: inline-flex; align-items: center; justify-content: center; gap: 8px;
  font-weight: 600; font-size: 14px; border-radius: 8px; padding: 11px 18px;
  transition: background .15s, transform .1s, box-shadow .15s, color .15s, border-color .15s;
  white-space: nowrap;
}
.btn:active { transform: translateY(1px); }
.btn--amazon { background: var(--accent); color: #140a02; font-weight: 700; }
.btn--amazon:hover { background: var(--accent-h); }
.btn--ghost { border: 1px solid var(--border-2); color: var(--text); background: var(--card); }
.btn--ghost:hover { border-color: var(--text-2); }
.btn--outline-accent { border: 1px solid color-mix(in srgb, var(--accent) 55%, transparent); color: var(--accent); }
.btn--outline-accent:hover { background: color-mix(in srgb, var(--accent) 12%, transparent); }

/* ---- stars ------------------------------------------------ */
.stars { display: inline-flex; align-items: center; gap: 6px; }
.stars .rate { color: var(--text); font-weight: 700; }
.stars .glyphs { color: var(--gold); letter-spacing: 1px; font-size: 12px; }
.stars .count { color: var(--text-2); font-size: 12px; }

/* ---- placeholder image tiles ------------------------------ */
.ph-tile {
  position: relative; overflow: hidden;
  background-color: #171717;
  background-image: repeating-linear-gradient(
    135deg, #1c1c1c 0 10px, #161616 10px 20px);
  border: 1px solid var(--border);
  display: flex; align-items: center; justify-content: center;
  color: var(--text-3);
}
.ph-tile span {
  font-family: var(--font-mono); font-size: 10px; letter-spacing: 0.08em;
  text-transform: uppercase; color: #6a6a6a;
  background: rgba(15,15,15,.65); padding: 3px 7px; border-radius: 4px;
  backdrop-filter: blur(2px);
}

/* ---- category pills --------------------------------------- */
.pill {
  display: inline-flex; align-items: center; gap: 7px;
  padding: 8px 15px; border-radius: 999px; font-size: 13px; font-weight: 500;
  border: 1px solid var(--border-2); color: var(--text); background: var(--card);
  transition: border-color .15s, background .15s, color .15s; white-space: nowrap;
}
.pill:hover { border-color: var(--accent); color: var(--accent); }
.pill--active { background: var(--accent); color: #140a02; border-color: var(--accent); font-weight: 600; }

/* ---- dividers / chips ------------------------------------- */
.cat-chip {
  font-size: 11px; font-weight: 700; letter-spacing: 0.06em; text-transform: uppercase;
  color: var(--accent); display: inline-block;
}
.disclosure {
  display: inline-flex; align-items: center; gap: 6px;
  font-size: 12px; color: var(--text-2);
}
.disclosure .i {
  width: 15px; height: 15px; border-radius: 50%; border: 1px solid var(--text-3);
  display: inline-flex; align-items: center; justify-content: center;
  font-size: 9px; font-weight: 700; font-style: normal; flex: 0 0 auto;
}

/* generic hover-elevate card */
.elev { transition: transform .16s ease, border-color .16s ease, box-shadow .16s ease; }
.elev:hover { transform: translateY(-3px); border-color: var(--border-2); box-shadow: 0 12px 30px rgba(0,0,0,.45); }

/* hide scrollbars inside scroll strips */
.no-sb { scrollbar-width: none; }
.no-sb::-webkit-scrollbar { display: none; }

/* marquee ticker (terminal direction) */
@keyframes ph-ticker { from { transform: translateX(0); } to { transform: translateX(-50%); } }
.ticker-track { display: inline-flex; animation: ph-ticker 38s linear infinite; }
.ph:hover .ticker-track { animation-play-state: paused; }

/* ---- responsive breakpoints ------------------------------- */
@media (max-width: 767px) {
  /* header */
  .ph-hdr { padding: 10px 16px !important; gap: 14px !important; }
  .ph-hdr-nav { display: none !important; }
  .ph-hdr-right { gap: 8px !important; }

  /* deal grid: 4-col → 2-col */
  .deal-grid { grid-template-columns: repeat(2, 1fr) !important; }

  /* inner page padding */
  .page-inner { padding-left: 16px !important; padding-right: 16px !important; }

  /* comparison */
  .comp-grid { grid-template-columns: 1fr !important; }

  /* categories grid */
  .cat-grid { grid-template-columns: 1fr !important; }

  /* about trust grid */
  .trust-grid { grid-template-columns: repeat(2, 1fr) !important; }

  /* footer layout */
  .ph-footer { flex-direction: column !important; gap: 16px !important; padding: 24px 16px !important; }
}

@media (min-width: 768px) and (max-width: 1023px) {
  /* tablet: 3-col deal grid */
  .deal-grid { grid-template-columns: repeat(3, 1fr) !important; }
}


.entry-content > *, .wp-block-post-content > * { margin-top: 0 !important; margin-block-start: 0 !important; margin-block: 0 !important; }
.ph { margin-top: -31px !important; }
